import { db } from './firebase-config.js';
import { collection, addDoc } from "firebase/firestore";

const recipeForm = document.getElementById('form-recipe');

recipeForm.addEventListener('submit', async (event) => {
    event.preventDefault();

    const ingredientRows = document.querySelectorAll('.ingredient-and-amount');
    const ingredients = [];

    ingredientRows.forEach(row => {
        const name = row.querySelector('.ing-name').value.trim();
        const amount = row.querySelector('.ing-amount').value.trim();

        if (name) {
            ingredients.push({
                name: name,
                amount: amount || "-"
            });
        }
    });

    const newRecipe = {
        title: document.getElementById('title-input').value.trim(),
        description: document.getElementById('description-input').value.trim(),
        ingredients: ingredients,
        process: document.getElementById('process-input').value.trim()
    };

    try {
        await addDoc(collection(db, "recipes"), newRecipe);
        alert("Рецепт успішно збережено!");
        
        window.location.href = "../index.html"; 
    } catch (error) {
        console.error(error);
        alert("Сталася помилка");
    }
});